36: func (hs *HTTPServer) getDSQueryEndpoint() web.Handler {
37: 	//nolint:staticcheck // not yet migrated to OpenFeature
38: 	if hs.Features.IsEnabledGlobally(featuremgmt.FlagQueryServiceRewrite) {
39: 		// rewrite requests from /ds/query to the new query service
40: 		namespaceMapper := request.GetNamespaceMapper(hs.Cfg)
41: 		return func(w http.ResponseWriter, r *http.Request) {
42: 			user, err := identity.GetRequester(r.Context())
43: 			if err != nil || user == nil {
44: 				errhttp.Write(r.Context(), fmt.Errorf("no user"), w)
45: 				return
46: 			}
47: 			r.URL.Path = "/apis/datasource.grafana.app/v0alpha1/namespaces/" + namespaceMapper(user.GetOrgID()) + "/query"
48: 			hs.clientConfigProvider.DirectlyServeHTTP(w, r)
49: 		}
50: 	}
51: 	return routing.Wrap(hs.QueryMetricsV2)
52: }
