54: // QueryMetricsV2 returns query metrics.
55: // swagger:route POST /ds/query datasources queryMetricsWithExpressions
56: //
57: // DataSource query metrics with expressions.
58: //
59: // If you are running Grafana Enterprise and have Fine-grained access control enabled
60: // you need to have a permission with action: `datasources:query`.
61: //
62: // Responses:
63: // 200: queryMetricsWithExpressionsRespons
64: // 207: queryMetricsWithExpressionsRespons
65: // 401: unauthorisedError
66: // 400: badRequestError
67: // 403: forbiddenError
68: // 500: internalServerError
69: func (hs *HTTPServer) QueryMetricsV2(c *contextmodel.ReqContext) response.Response {
70: 	reqDTO := dtos.MetricRequest{}
71: 	if err := web.Bind(c.Req, &reqDTO); err != nil {
72: 		return response.Error(http.StatusBadRequest, "bad request data", err)
73: 	}
74: 
75: 	handleTimeInQuery := c.Req.Header.Get("X-Query-V2") == "true"
76: 
77: 	var resp *backend.QueryDataResponse
78: 	var err error
79: 
80: 	hs.log.Debug("QueryMetricsV2: request received", "time_in_query", handleTimeInQuery)
81: 	if handleTimeInQuery {
82: 		resp, err = hs.queryDataService.QueryDataNew(c.Req.Context(), c.SignedInUser, c.SkipDSCache, reqDTO)
83: 	} else {
84: 		resp, err = hs.queryDataService.QueryData(c.Req.Context(), c.SignedInUser, c.SkipDSCache, reqDTO)
85: 	}
86: 
87: 	if err != nil {
88: 		return hs.handleQueryMetricsError(err)
89: 	}
90: 	return hs.toJsonStreamingResponse(c.Req.Context(), resp)
91: }
