93: func (hs *HTTPServer) toJsonStreamingResponse(ctx context.Context, qdr *backend.QueryDataResponse) response.Response {
94: 	statusCode := http.StatusOK
95: 	for _, res := range qdr.Responses {
96: 		if res.Error != nil {
97: 			statusCode = http.StatusBadRequest
98: 			break
99: 		}
100: 	}
101: 
102: 	if statusCode == http.StatusBadRequest {
103: 		// an error in the response we treat as downstream.
104: 		requestmeta.WithDownstreamStatusSource(ctx)
105: 	}
106: 
107: 	return response.JSONStreaming(statusCode, qdr)
108: }
