103: // QueryData processes queries and returns query responses. It handles queries to single or mixed datasources, as well as expressions.
104: func (s *ServiceImpl) queryData(ctx context.Context, user identity.Requester, skipDSCache bool, reqDTO dtos.MetricRequest, supportLocaltimeRange bool) (*backend.QueryDataResponse, error) {
105: 	fromAlert := false
106: 	for header, val := range s.headers {
107: 		if header == models.FromAlertHeaderName && val == "true" {
108: 			fromAlert = true
109: 		}
110: 	}
111: 	// Parse the request into parsed queries grouped by datasource uid
112: 	parsedReq, err := s.parseMetricRequest(ctx, user, skipDSCache, reqDTO, supportLocaltimeRange)
113: 	if err != nil {
114: 		return nil, err
115: 	}
116: 
117: 	// If there are expressions, handle them and return
118: 	if parsedReq.hasExpression || fromAlert {
119: 		return s.handleExpressions(ctx, user, parsedReq)
120: 	}
121: 	// If there is only one datasource, query it and return
122: 	if len(parsedReq.parsedQueries) == 1 {
123: 		return s.handleQuerySingleDatasource(ctx, user, parsedReq)
124: 	}
125: 	// If there are multiple datasources, handle their queries concurrently and return the aggregate result
126: 	return s.executeConcurrentQueries(ctx, user, skipDSCache, reqDTO, parsedReq.parsedQueries)
127: }
