249: // handleExpressions handles queries when there is an expression.
250: func (s *ServiceImpl) handleExpressions(ctx context.Context, user identity.Requester, parsedReq *parsedRequest) (*backend.QueryDataResponse, error) {
251: 	exprReq := expr.Request{
252: 		Queries: []expr.Query{},
253: 	}
254: 
255: 	if user != nil { // for passthrough authentication, SSE does not authenticate
256: 		exprReq.User = user
257: 		exprReq.OrgId = user.GetOrgID()
258: 	}
259: 
260: 	for _, pq := range parsedReq.getFlattenedQueries() {
261: 		if pq.datasource == nil {
262: 			return nil, ErrMissingDataSourceInfo.Build(errutil.TemplateData{
263: 				Public: map[string]any{
264: 					"RefId": pq.query.RefID,
265: 				},
266: 			})
267: 		}
268: 
269: 		exprReq.Queries = append(exprReq.Queries, expr.Query{
270: 			JSON:          pq.query.JSON,
271: 			Interval:      pq.query.Interval,
272: 			RefID:         pq.query.RefID,
273: 			MaxDataPoints: pq.query.MaxDataPoints,
274: 			QueryType:     pq.query.QueryType,
275: 			DataSource:    pq.datasource,
276: 			TimeRange: expr.AbsoluteTimeRange{
277: 				From: pq.query.TimeRange.From,
278: 				To:   pq.query.TimeRange.To,
279: 			},
280: 		})
281: 	}
282: 
283: 	qdr, err := s.expressionService.TransformData(ctx, time.Now(), &exprReq) // use time now because all queries have absolute time range
284: 	if err != nil {
285: 		return nil, fmt.Errorf("expression request error: %w", err)
286: 	}
287: 	return qdr, nil
288: }
