387: // parseRequest parses a request into parsed queries grouped by datasource uid
388: func (s *ServiceImpl) parseMetricRequest(ctx context.Context, user identity.Requester, skipDSCache bool, reqDTO dtos.MetricRequest, supportLocalTimeRange bool) (*parsedRequest, error) {
389: 	if len(reqDTO.Queries) == 0 {
390: 		return nil, ErrNoQueriesFound
391: 	}
392: 
393: 	req := &parsedRequest{
394: 		hasExpression: false,
395: 		parsedQueries: make(map[string][]parsedQuery),
396: 		dsTypes:       make(map[string]bool),
397: 	}
398: 
399: 	// Parse the queries and store them by datasource
400: 	datasourcesByUid := map[string]*datasources.DataSource{}
401: 	for _, query := range reqDTO.Queries {
402: 		ds, err := s.getDataSourceFromQuery(ctx, user, skipDSCache, query, datasourcesByUid)
403: 		if err != nil {
404: 			return nil, err
405: 		}
406: 		if ds == nil {
407: 			return nil, ErrInvalidDatasourceID
408: 		}
409: 
410: 		datasourcesByUid[ds.UID] = ds
411: 		if expr.NodeTypeFromDatasourceUID(ds.UID) != expr.TypeDatasourceNode {
412: 			req.hasExpression = true
413: 		} else {
414: 			req.dsTypes[ds.Type] = true
415: 		}
416: 
417: 		if _, ok := req.parsedQueries[ds.UID]; !ok {
418: 			req.parsedQueries[ds.UID] = []parsedQuery{}
419: 		}
420: 
421: 		var timeRange gtime.TimeRange
422: 		if supportLocalTimeRange {
423: 			from, to, err := getTimeRange(query, reqDTO.From, reqDTO.To)
424: 			if err != nil {
425: 				return nil, err
426: 			}
427: 			timeRange = gtime.NewTimeRange(from, to)
428: 		} else {
429: 			timeRange = gtime.NewTimeRange(reqDTO.From, reqDTO.To)
430: 		}
431: 
432: 		modelJSON, err := queryToJson(query, supportLocalTimeRange)
433: 		if err != nil {
434: 			return nil, err
435: 		}
436: 
437: 		pq := parsedQuery{
438: 			datasource: ds,
439: 			query: backend.DataQuery{
440: 				TimeRange: backend.TimeRange{
441: 					From: timeRange.GetFromAsTimeUTC(),
442: 					To:   timeRange.GetToAsTimeUTC(),
443: 				},
444: 				RefID:         query.Get("refId").MustString("A"),
445: 				MaxDataPoints: query.Get("maxDataPoints").MustInt64(100),
446: 				Interval:      time.Duration(query.Get("intervalMs").MustInt64(1000)) * time.Millisecond,
447: 				QueryType:     query.Get("queryType").MustString(""),
448: 				JSON:          modelJSON,
449: 			},
450: 			rawQuery: query,
451: 		}
452: 		req.parsedQueries[ds.UID] = append(req.parsedQueries[ds.UID], pq)
453: 
454: 		s.log.Debug("Processed metrics query",
455: 			"ref_id", pq.query.RefID,
456: 			"from", timeRange.GetFromAsMsEpoch(),
457: 			"to", timeRange.GetToAsMsEpoch(),
458: 			"interval", pq.query.Interval.Milliseconds(),
459: 			"max_data_points", pq.query.MaxDataPoints,
460: 			"query", string(modelJSON))
461: 	}
462: 
463: 	return req, req.validateRequest(ctx)
464: }
