466: func (s *ServiceImpl) getDataSourceFromQuery(ctx context.Context, user identity.Requester, skipDSCache bool, query *simplejson.Json, history map[string]*datasources.DataSource) (*datasources.DataSource, error) {
467: 	var err error
468: 	uid := query.Get("datasource").Get("uid").MustString()
469: 
470: 	// before 8.3 special types could be sent as datasource (expr)
471: 	if uid == "" {
472: 		uid = query.Get("datasource").MustString()
473: 	}
474: 
475: 	// check cache value
476: 	ds, ok := history[uid]
477: 	if ok {
478: 		return ds, nil
479: 	}
480: 
481: 	if kind := expr.NodeTypeFromDatasourceUID(uid); kind != expr.TypeDatasourceNode {
482: 		return expr.DataSourceModelFromNodeType(kind)
483: 	}
484: 
485: 	if uid == grafanads.DatasourceUID {
486: 		return grafanads.DataSourceModel(user.GetOrgID()), nil
487: 	}
488: 
489: 	if uid != "" {
490: 		ds, err = s.dataSourceCache.GetDatasourceByUID(ctx, uid, user, skipDSCache)
491: 		if err != nil {
492: 			return nil, err
493: 		}
494: 		return ds, nil
495: 	}
496: 
497: 	// use datasourceId if it exists
498: 	id := query.Get("datasourceId").MustInt64(0)
499: 	if id > 0 {
500: 		ds, err = s.dataSourceCache.GetDatasource(ctx, id, user, skipDSCache)
501: 		if err != nil {
502: 			return nil, err
503: 		}
504: 		return ds, nil
505: 	}
506: 
