114: func (s *Service) CallResource(ctx context.Context, req *backend.CallResourceRequest, sender backend.CallResourceResponseSender) error {
115: 	if req == nil {
116: 		return errNilRequest
117: 	}
118: 
119: 	if sender == nil {
120: 		return errNilSender
121: 	}
122: 
123: 	p, exists := s.plugin(ctx, req.PluginContext.PluginID, req.PluginContext.PluginVersion)
124: 	if !exists {
125: 		return plugins.ErrPluginNotRegistered
126: 	}
127: 
128: 	removeConnectionHeaders(req.Headers)
129: 	removeHopByHopHeaders(req.Headers)
130: 	removeNonAllowedHeaders(req.Headers)
131: 
132: 	processedStreams := 0
133: 	wrappedSender := backend.CallResourceResponseSenderFunc(func(res *backend.CallResourceResponse) error {
134: 		// Expected that headers and status are only part of first stream
135: 		if processedStreams == 0 && res != nil {
136: 			if len(res.Headers) > 0 {
137: 				removeConnectionHeaders(res.Headers)
138: 				removeHopByHopHeaders(res.Headers)
139: 				removeNonAllowedHeaders(res.Headers)
140: 			} else {
141: 				res.Headers = map[string][]string{}
142: 			}
143: 
144: 			SetCSPHeader(res.Headers)
145: 			ensureContentTypeHeader(res)
146: 		}
147: 
148: 		processedStreams++
149: 		return sender.Send(res)
150: 	})
151: 
152: 	err := p.CallResource(ctx, req, wrappedSender)
153: 	if err != nil {
154: 		if errors.Is(err, context.Canceled) {
155: 			return plugins.ErrPluginRequestCanceledErrorBase.Errorf("client: call resource request canceled: %w", err)
156: 		}
157: 
158: 		return plugins.ErrPluginRequestFailureErrorBase.Errorf("client: failed to call resources: %w", err)
159: 	}
160: 
161: 	return nil
162: }
