319: // removeConnectionHeaders removes hop-by-hop headers listed in the "Connection" header of h.
320: // See RFC 7230, section 6.1
321: //
322: // Based on https://github.com/golang/go/blob/dc04f3ba1f25313bc9c97e728620206c235db9ee/src/net/http/httputil/reverseproxy.go#L411-L421
323: func removeConnectionHeaders(h map[string][]string) {
324: 	for _, f := range h["Connection"] {
325: 		for _, sf := range strings.Split(f, ",") {
326: 			if sf = textproto.TrimString(sf); sf != "" {
327: 				for k := range h {
328: 					if textproto.CanonicalMIMEHeaderKey(sf) == textproto.CanonicalMIMEHeaderKey(k) {
329: 						delete(h, k)
330: 						break
331: 					}
332: 				}
333: 			}
334: 		}
335: 	}
336: }
337: 
338: // Hop-by-hop headers. These are removed when sent to the backend.
339: // As of RFC 7230, hop-by-hop headers are required to appear in the
340: // Connection header field. These are the headers defined by the
341: // obsoleted RFC 2616 (section 13.5.1) and are used for backward
342: // compatibility.
343: //
344: // Copied from https://github.com/golang/go/blob/dc04f3ba1f25313bc9c97e728620206c235db9ee/src/net/http/httputil/reverseproxy.go#L171-L186
345: var hopHeaders = []string{
346: 	"Connection",
347: 	"Proxy-Connection", // non-standard but still sent by libcurl and rejected by e.g. google
348: 	"Keep-Alive",
349: 	"Proxy-Authenticate",
350: 	"Proxy-Authorization",
351: 	"Te",      // canonicalized version of "TE"
352: 	"Trailer", // not Trailers per URL above; https://www.rfc-editor.org/errata_search.php?eid=4522
353: 	"Transfer-Encoding",
354: 	"Upgrade",
355: 	"User-Agent",
356: }
357: 
358: // removeHopByHopHeaders removes hop-by-hop headers. Especially
359: // important is "Connection" because we want a persistent
360: // connection, regardless of what the client sent to us.
361: //
362: // Based on https://github.com/golang/go/blob/dc04f3ba1f25313bc9c97e728620206c235db9ee/src/net/http/httputil/reverseproxy.go#L276-L281
363: func removeHopByHopHeaders(h map[string][]string) {
364: 	for _, hh := range hopHeaders {
365: 		for k := range h {
366: 			if hh == textproto.CanonicalMIMEHeaderKey(k) {
367: 				delete(h, k)
368: 				break
369: 			}
370: 		}
371: 	}
372: }
373: 
374: func removeNonAllowedHeaders(h map[string][]string) {
375: 	for k := range h {
376: 		if textproto.CanonicalMIMEHeaderKey(k) == setCookieHeaderName {
377: 			delete(h, k)
378: 		}
379: 	}
380: }
381: 
382: // ensureContentTypeHeader makes sure a content type always is returned in response.
383: func ensureContentTypeHeader(res *backend.CallResourceResponse) {
384: 	if res == nil {
385: 		return
386: 	}
387: 
388: 	var hasContentType bool
389: 	for k := range res.Headers {
390: 		if textproto.CanonicalMIMEHeaderKey(k) == contentTypeHeaderName {
391: 			hasContentType = true
392: 			break
393: 		}
394: 	}
395: 
396: 	if !hasContentType && res.Status != http.StatusNoContent {
397: 		res.Headers[contentTypeHeaderName] = []string{defaultContentType}
398: 	}
399: }
